mapper.select:
SELECT e.employee_id, e.employee_no, e.employee_name, e.dept_id, d.dept_name, d.dept_code, e.position_id, p.position_name, p.position_code, p.position_level, e.email, e.phone, e.keycloak_user_id, e.hire_date, e.status, e.created_at, e.updated_at FROM platform_v3.org_employee e INNER JOIN platform_v3.org_department d ON e.dept_id = d.dept_id INNER JOIN platform_v3.org_position p ON e.position_id = p.position_id WHERE 1=1
AND (e.employee_name LIKE '%' || #{keyword} || '%' OR e.employee_no LIKE '%' || #{keyword} || '%' OR e.email LIKE '%' || #{keyword} || '%' OR e.keycloak_user_id LIKE '%' || #{keyword} || '%')
AND e.dept_id = #{deptId} AND e.status = #{status} ORDER BY e.employee_no OFFSET #{offset} LIMIT #{limit}

SELECT COUNT(*) FROM platform_v3.org_employee e WHERE 1=1
AND (e.employee_name LIKE '%' || #{keyword} || '%' OR e.employee_no LIKE '%' || #{keyword} || '%' OR e.email LIKE '%' || #{keyword} || '%' OR e.keycloak_user_id LIKE '%' || #{keyword} || '%')
AND e.dept_id = #{deptId} AND e.status = #{status}

mapper.update:
UPDATE platform_v3.org_employee
   SET status = #{status}, updated_at = NOW()
 WHERE employee_id = #{employeeId}

UPDATE platform_v3.org_employee
   SET keycloak_user_id = #{keycloakUserId}, updated_at = NOW()
 WHERE employee_id = #{employeeId}

